# Propositional Logic Operations in Python
# Basic operators for propositional logic

def NOT(p):
    return not p

def AND(p, q):
    return p and q

def OR(p, q):
    return p or q

def IMPLIES(p, q):
    return not p or q  # p -> q is equivalent to ¬p ∨ q

def IFF(p, q):
    return (p and q) or (not p and not q)  # p ↔ q

# Generate truth table for (p ∧ q) → (p ∨ r)
def compound_proposition(p, q, r):
    return IMPLIES(AND(p, q), OR(p, r))

# Print truth table
print("Truth Table for (p ∧ q) → (p ∨ r):")
print("p	q	r	result")
print("-" * 30)

for p in [False, True]:
    for q in [False, True]:
        for r in [False, True]:
            result = compound_proposition(p, q, r)
            print(f"{int(p)}	{int(q)}	{int(r)}	{int(result)}")

