# Backward Chaining Inference Engine for First-Order Logic
# Demonstrates resolution and unification

class Term:
    """Represents variables and constants in FOL"""
    def __init__(self, name, is_variable=False):
        self.name = name
        self.is_variable = is_variable

    def __repr__(self):
        return self.name

class Predicate:
    """Represents atomic formulas in FOL"""
    def __init__(self, name, terms):
        self.name = name
        self.terms = terms  # List of Term objects

    def __repr__(self):
        terms_str = ", ".join(str(t) for t in self.terms)
        return f"{self.name}({terms_str})"

def unify(term1, term2, substitution):
    """Unification algorithm - finds substitution to make terms equal"""
    if substitution is None:
        return None

    if term1 == term2:
        return substitution

    # If term1 is a variable, bind it to term2
    if term1.is_variable:
        return {**substitution, term1.name: term2}

    # If term2 is a variable, bind it to term1
    if term2.is_variable:
        return {**substitution, term2.name: term1}

    return None

def apply_substitution(predicate, substitution):
    """Apply substitution to a predicate"""
    new_terms = []
    for term in predicate.terms:
        if term.is_variable and term.name in substitution:
            new_terms.append(substitution[term.name])
        else:
            new_terms.append(term)
    return Predicate(predicate.name, new_terms)

class InferenceEngine:
    def __init__(self):
        self.rules = []  # List of (antecedents, consequent) pairs
        self.facts = []  # List of known predicates

    def add_fact(self, predicate):
        self.facts.append(predicate)

    def add_rule(self, antecedents, consequent):
        """Add rule: antecedent1 ∧ antecedent2 → consequent"""
        self.rules.append((antecedents, consequent))

    def backward_chain(self, goal, substitution=None):
        """Backward chaining algorithm - attempts to prove goal"""
        if substitution is None:
            substitution = {}

        # Print current goal
        goal_applied = apply_substitution(goal, substitution)
        print(f"Goal: {goal_applied}")

        # Check if goal matches any fact
        for fact in self.facts:
            unified = unify(fact, goal_applied, substitution)
            if unified is not None:
                print(f"  ↳ Fact match: {fact}")
                return unified

        # Try to prove via rules
        for antecedents, consequent in self.rules:
            # Try to unify goal with rule consequent
            unified = unify(consequent, goal_applied, substitution)
            if unified is not None:
                print(f"  ↳ Rule applicable: {antecedents} → {consequent}")

                # Recursively prove all antecedents
                current_sub = unified
                for ant in antecedents:
                    current_sub = self.backward_chain(ant, current_sub)
                    if current_sub is None:
                        break

                if current_sub is not None:
                    return current_sub

        return None

# Example: AI Diagnostic System
engine = InferenceEngine()

# Define terms
x = Term('x', True)  # Variable
alice = Term('Alice', False)  # Constant
flu = Term('flu', False)
cold = Term('cold', False)
fever = Term('fever', False)
cough = Term('cough', False)

# Add facts
engine.add_fact(Predicate('has_symptom', [alice, fever]))
engine.add_fact(Predicate('has_symptom', [alice, cough]))

# Add rules
# has_symptom(x, fever) ∧ has_symptom(x, cough) → has(x, flu)
engine.add_rule(
    [Predicate('has_symptom', [x, fever]), 
     Predicate('has_symptom', [x, cough])],
    Predicate('has', [x, flu])
)

# has(x, flu) → needs_medicine(x)
engine.add_rule(
    [Predicate('has', [x, flu])],
    Predicate('needs_medicine', [x])
)

print("=" * 50)
print("Backward Chaining: Does Alice need medicine?")
print("=" * 50)
result = engine.backward_chain(Predicate('needs_medicine', [alice]))
print(f"\nResult: {result}")

if result:
    print("\nConclusion: Alice needs medicine for flu")
else:
    print("\nConclusion: Cannot prove Alice needs medicine")
